&ClInsc = &CliInsAux &NewInscricao = &CliInsAux
//Substituo os caracteres invalidos. if &ClInsc = 'ISENTO' OR &ClInsc = 'EM ANDAMENTO' or &ClInsc.IsEmpty() &InscricaoValida = 'S' return endif
&Inscricao = strReplace(&ClInsc,'-','') &Inscricao = strReplace(&Inscricao,'.','') &Inscricao = strReplace(&Inscricao,'/','') &Inscricao = strReplace(&Inscricao,',','') &Inscricao = strReplace(&Inscricao,' ','') &Inscricao = trim(&Inscricao)
&Inscricao = padl(&Inscricao,16,'0')
//Acre If &Uf = 'AC' &Inscricao = substr(&Inscricao,4,13) If len(&Inscricao) <> 13 &InscricaoValida = 'N' Else //1º Dígito &Calculo = val(substr(&Inscricao,1,1))*4 + val(substr(&Inscricao,2,1))*3 + val(substr(&Inscricao,3,1))*2 + val(substr(&Inscricao,4,1))*9 + val(substr(&Inscricao,5,1))*8 + val(substr(&Inscricao,6,1))*7 + val(substr(&Inscricao,7,1))*6 + val(substr(&Inscricao,8,1))*5 + val(substr(&Inscricao,9,1))*4 + val(substr(&Inscricao,10,1))*3 + val(substr(&Inscricao,11,1))*2 &Resto = &Calculo - (int(&Calculo/11)*11) &Digito = 11-&Resto if &Digito >= 10 &Digito = 0 Endif
If val(substr(&Inscricao,12,1))= &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' return Endif
//2º Dígito &Calculo = val(substr(&Inscricao,1,1))*5 + val(substr(&Inscricao,2,1))*4 + val(substr(&Inscricao,3,1))*3 + val(substr(&Inscricao,4,1))*2 + val(substr(&Inscricao,5,1))*9 + val(substr(&Inscricao,6,1))*8 + val(substr(&Inscricao,7,1))*7 + val(substr(&Inscricao,8,1))*6 + val(substr(&Inscricao,9,1))*5 + val(substr(&Inscricao,10,1))*4 + val(substr(&Inscricao,11,1))*3 + val(substr(&Inscricao,12,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 &Digito = 11-&Resto If &Digito >= 10 &Digito = 0 Endif If val(substr(&Inscricao,13,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Endif Endif
return Endif
//alagoas If &Uf = 'AL' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 .or. substr(&Inscricao,1,2) <> '24' &InscricaoValida = 'N' Else do 'Soma' &Calculo = &Calculo*10 &Resto = &Calculo - int(&Calculo/11)*11 &Digito = &Resto If &Resto = 10 &Digito = 0 Endif If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif return Endif
//Amapá If &Uf = 'AP' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 .or. substr(&Inscricao,1,2) <> '03' &InscricaoValida = 'N' else If &Inscricao >= '030000010' .and. &Inscricao <= '030170009' &P = 5 &d = 0 else If &Inscricao >= '030170010' .and. &Inscricao <= '030190229' &P = 9 &d = 1 Else &P = 0 &d = 0 Endif Endif do 'Soma' &Calculo = &Calculo + &P &Resto = &Calculo - int(&Calculo/11)*11 &Digito = 11-&Resto If &Digito = 10 &Digito = 0 Endif If &Digito = 11 &Digito = &d Endif If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif
return endif
//Amazonas If &Uf = 'AM' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 &InscricaoValida = 'N' Else do 'Soma' if &Calculo < 11 &Digito = 11-&Calculo Endif If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Endif endif return Endif
//Bahia If &Uf = 'BA'
&Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 &InscricaoValida = 'N' Else
if substr(&Inscricao,1,1) = '0' &Inscricao = substr(&Inscricao,2,8)
If substr(&Inscricao,1,1) <> '6' .and. substr(&Inscricao,1,1) <> '7' .and. substr(&Inscricao,1,1) <> '9' //Calculo pelo módulo 10 - Primeiro digito = 0,1,2,3,4,5 ou 8 //2º dígito &Calculo = val(substr(&Inscricao,1,1))*7 + val(substr(&Inscricao,2,1))*6 + val(substr(&Inscricao,3,1))*5 + val(substr(&Inscricao,4,1))*4 + val(substr(&Inscricao,5,1))*3 + val(substr(&Inscricao,6,1))*2 &Resto = &Calculo - int(&Calculo/10)*10 &Digito = 10 - &Resto If &Resto = 0 &Digito = 0 Endif
If val(substr(&Inscricao,8,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Return endif
//1º Digito &Calculo = val(substr(&Inscricao,1,1))*8 + val(substr(&Inscricao,2,1))*7 + val(substr(&Inscricao,3,1))*6 + val(substr(&Inscricao,4,1))*5 + val(substr(&Inscricao,5,1))*4 + val(substr(&Inscricao,6,1))*3 + val(substr(&Inscricao,8,1))*2 &Resto = &Calculo - int(&Calculo/10)*10 &Digito = 10-&Resto if &Resto = 0 &Digito = 0 endif If val(substr(&Inscricao,7,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' endif Else //Modulo 11 - Primeiro digitos = 6,7 ou 9 //2º Dígito &Calculo = val(substr(&Inscricao,1,1))*7 + val(substr(&Inscricao,2,1))*6 + val(substr(&Inscricao,3,1))*5 + val(substr(&Inscricao,4,1))*4 + val(substr(&Inscricao,5,1))*3 + val(substr(&Inscricao,6,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 &Digito = 11 - &Resto If &Resto = 0 .or. &Resto = 1 &Digito = 0 Endif If val(substr(&Inscricao,8,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Return endif
//1º Digito &Calculo = val(substr(&Inscricao,1,1))*8 + val(substr(&Inscricao,2,1))*7 + val(substr(&Inscricao,3,1))*6 + val(substr(&Inscricao,4,1))*5 + val(substr(&Inscricao,5,1))*4 + val(substr(&Inscricao,6,1))*3 + val(substr(&Inscricao,8,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 &Digito = 11-&Resto if &Resto = 0 or &Resto = 1 &Digito = 0 endif If val(substr(&Inscricao,7,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' endif Endif
else
// BA com 9 digitos If substr(&Inscricao,2,1) <> '6' .and. substr(&Inscricao,2,1) <> '7' .and. substr(&Inscricao,2,1) <> '9' //Calculo pelo módulo 10 - Primeiro digito = 0,1,2,3,4,5 ou 8 //2º dígito &Calculo = val(substr(&Inscricao,1,1))*8 + val(substr(&Inscricao,2,1))*7 + val(substr(&Inscricao,3,1))*6 + val(substr(&Inscricao,4,1))*5 + val(substr(&Inscricao,5,1))*4 + val(substr(&Inscricao,6,1))*3+ val(substr(&Inscricao,7,1))*2
&Resto = &Calculo - int(&Calculo/10)*10 &Digito = 10 - &Resto If &Resto = 0 &Digito = 0 Endif
If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Return endif
//1º Digito &Calculo = val(substr(&Inscricao,1,1))*9 + val(substr(&Inscricao,2,1))*8 + val(substr(&Inscricao,3,1))*7 + val(substr(&Inscricao,4,1))*6 + val(substr(&Inscricao,5,1))*5 + val(substr(&Inscricao,6,1))*4 + val(substr(&Inscricao,7,1))*3+ val(substr(&Inscricao,9,1))*2 &Resto = &Calculo - int(&Calculo/10)*10 &Digito = 10-&Resto if &Resto = 0 &Digito = 0 endif If val(substr(&Inscricao,8,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' endif Else //Modulo 11 - Primeiro digitos = 6,7 ou 9 //2º Dígito &Calculo = val(substr(&Inscricao,1,1))*8 + val(substr(&Inscricao,2,1))*7 + val(substr(&Inscricao,3,1))*6 + val(substr(&Inscricao,4,1))*5 + val(substr(&Inscricao,5,1))*4 + val(substr(&Inscricao,6,1))*3 + val(substr(&Inscricao,7,1))*2
&Resto = &Calculo - int(&Calculo/11)*11 &Digito = 11 - &Resto If &Resto = 0 or &Resto = 1 &Digito = 0 Endif If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Return endif
//1º Digito &Calculo = val(substr(&Inscricao,1,1))*9 + val(substr(&Inscricao,2,1))*8 + val(substr(&Inscricao,3,1))*7 + val(substr(&Inscricao,4,1))*6 + val(substr(&Inscricao,5,1))*5 + val(substr(&Inscricao,6,1))*4 + val(substr(&Inscricao,7,1))*3+ val(substr(&Inscricao,9,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 &Digito = 11-&Resto if &Resto = 0 or &Resto = 1 &Digito = 0 endif If val(substr(&Inscricao,8,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' endif Endif EndIf Endif
return Endif
//Ceará If &Uf = 'CE' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 &InscricaoValida = 'N' else do 'Soma' If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Endif Endif return endif
//distrito Federal If &Uf = 'DF' &Inscricao = substr(&Inscricao,4,13) //08027112001 97
If len(&Inscricao) <> 13 .or. (substr(&Inscricao,1,2) <> '07' and substr(&Inscricao,1,2) <> '08') &InscricaoValida = 'N' else //1º Digito &Calculo = val(substr(&Inscricao,1,1))*4 + val(substr(&Inscricao,2,1))*3 + val(substr(&Inscricao,3,1))*2 + val(substr(&Inscricao,4,1))*9 + val(substr(&Inscricao,5,1))*8 + val(substr(&Inscricao,6,1))*7 + val(substr(&Inscricao,7,1))*6 + val(substr(&Inscricao,8,1))*5 + val(substr(&Inscricao,9,1))*4 + val(substr(&Inscricao,10,1))*3 + val(substr(&Inscricao,11,1))*2 &Resto = &Calculo - int(&Calculo/11)*11
&Digito = 11-&Resto if &Digito >= 10 &Digito = 0 Endif If val(substr(&Inscricao,12,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' return Endif
//2º Dígito &Calculo = val(substr(&Inscricao,1,1))*5 + val(substr(&Inscricao,2,1))*4 + val(substr(&Inscricao,3,1))*3 + val(substr(&Inscricao,4,1))*2 + val(substr(&Inscricao,5,1))*9 + val(substr(&Inscricao,6,1))*8 + val(substr(&Inscricao,7,1))*7 + val(substr(&Inscricao,8,1))*6 + val(substr(&Inscricao,9,1))*5 + val(substr(&Inscricao,10,1))*4 + val(substr(&Inscricao,11,1))*3 + val(substr(&Inscricao,12,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 &Digito = 11-&Resto If &Digito >= 10 &Digito = 0 Endif If val(substr(&Inscricao,13,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' endif Endif return Endif
//Espírito Santo If &Uf = 'ES' &Inscricao = substr(&Inscricao,8,9)
if len(&Inscricao) <> 9 &InscricaoValida = 'N' else do 'Soma' If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' endif Endif return endif
//Goiás if &Uf = 'GO' &Inscricao = substr(&Inscricao,8,9)
if len(&Inscricao) <> 9 .or. (substr(&Inscricao,1,2) <> '10' .and. substr(&Inscricao,1,2)<>'11' .and. substr(&Inscricao,1,2) <> '15' and substr(&Inscricao,1,2) <> '20') &InscricaoValida = 'N' Else do 'Soma' If &Resto = 1 If &Inscricao >= '101031050' .and. &Inscricao <= '101199979' &Digito = 1 Else &Digito = 0 Endif Endif If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' endif Endif return Endif
//Maranhão If &uf = 'MA' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 &InscricaoValida = 'N' Else do 'Soma' If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' endif endif return endif
//Mato Grosso If &Uf = 'MT' &Inscricao = substr(&Inscricao,6,11)
If len(&Inscricao) <> 11 &InscricaoValida = 'N' Else &Calculo = val(substr(&Inscricao,1,1))*3 + val(substr(&Inscricao,2,1))*2 + val(substr(&Inscricao,3,1))*9 + val(substr(&Inscricao,4,1))*8 + val(substr(&Inscricao,5,1))*7 + val(substr(&Inscricao,6,1))*6 + val(substr(&Inscricao,7,1))*5 + val(substr(&Inscricao,8,1))*4 + val(substr(&Inscricao,9,1))*3 + val(substr(&Inscricao,10,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 If &Resto <= 1 &Digito = 0 Else &Digito = 11-&Resto endif If val(substr(&Inscricao,11,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' endif Endif return Endif
//Mato Grosso do Sul If &uf = 'MS' &Inscricao = substr(&Inscricao,8,9)
if len(&Inscricao) <> 9 .or. substr(&Inscricao,1,2) <> '28' &InscricaoValida = 'N' Else do 'Soma' if val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' endif Endif return Endif
//Minas Gerais If &Uf = 'MG' &Inscricao = substr(&Inscricao,4,13)
If len(&Inscricao) <> 13 &InscricaoValida = 'N' Else //1º Dígito &ClInsc = &Inscricao &Inscricao = substr(&Inscricao,1,3) + '0' + substr(&Inscricao,4,10) &Cont = 1 &Calculo = 0 Do while &Cont <= 12 &Resto = &Cont - int(&Cont/2)*2 If &Resto <> 0 &Calculo += val(substr(&Inscricao,&Cont,1)) Else &d = val(substr(&Inscricao,&Cont,1))*2 If &d < 10 &Calculo += &d Else If &d = 10 &Calculo += 1 Else If &d = 12 &Calculo += 3 Else If &d = 14 &Calculo += 5 Else If &d = 16 &Calculo += 7 Else If &d = 18 &Calculo += 9 Endif Endif Endif Endif Endif endif Endif
&Cont += 1 Enddo If &Calculo >= 0 .and. &Calculo <= 10 &Digito = 10 - &Calculo else if &Calculo > 10 .and. &Calculo <= 20 &Digito = 20 - &Calculo Else If &Calculo > 20 .and. &Calculo <= 30 &Digito = 30 - &Calculo else If &Calculo > 30 .and. &Calculo <= 40 &Digito = 40 - &Calculo else If &Calculo > 40 .and. &Calculo <= 50 &Digito = 50 - &Calculo else If &Calculo > 50 .and. &Calculo <= 60 &Digito = 60 - &Calculo else If &Calculo > 60 .and. &Calculo <= 70 &Digito = 70 - &Calculo else If &Calculo > 70 .and. &Calculo <= 80 &Digito = 80 - &Calculo else If &Calculo > 80 .and. &Calculo <= 90 &Digito = 90 - &Calculo else If &Calculo > 90 &Digito = 100 - &Calculo Endif Endif Endif Endif Endif Endif Endif Endif Endif Endif
&Inscricao = &ClInsc If val(substr(&Inscricao,12,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Return Endif
//2º Dígito &Calculo = val(substr(&Inscricao,12,1))*2 + val(substr(&Inscricao,11,1))*3 + val(substr(&Inscricao,10,1))*4 + val(substr(&Inscricao,9,1))*5 + val(substr(&Inscricao,8,1))*6 + val(substr(&Inscricao,7,1))*7 + val(substr(&Inscricao,6,1))*8 + val(substr(&Inscricao,5,1))*9 + val(substr(&Inscricao,4,1))*10 + val(substr(&Inscricao,3,1))*11 + val(substr(&Inscricao,2,1))*2 + val(substr(&Inscricao,1,1))*3 &Resto = &Calculo - int(&Calculo/11)*11 If &Resto <= 1 &Digito = 0 else &Digito = 11-&Resto Endif If val(substr(&Inscricao,13,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif return Endif
//Pará If &Uf = 'PA'
&Inscricao = substr(&Inscricao,8,9) &Prefixo = substr(&Inscricao,1,2) If len(&Inscricao) <> 9 or (&Prefixo <> '15' and &Prefixo <> '75' and &Prefixo <> '76' and &Prefixo <> '77' and &Prefixo <> '78' and &Prefixo <> '79') &InscricaoValida = 'N' return Else do 'Soma' If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif return Endif
//Paraíba If &Uf = 'PB' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 &InscricaoValida = 'N' Else do 'Soma' If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif return Endif
//Paraná If &Uf = 'PR' &Inscricao = substr(&Inscricao,7,10)
if len(&Inscricao) <> 10 &InscricaoValida = 'N' Else //1º Dígito &Calculo = val(substr(&Inscricao,1,1))*3 + val(Substr(&Inscricao,2,1))*2 + val(Substr(&Inscricao,3,1))*7 + val(Substr(&Inscricao,4,1))*6 + val(Substr(&Inscricao,5,1))*5 + val(Substr(&Inscricao,6,1))*4 + val(Substr(&Inscricao,7,1))*3 + val(Substr(&Inscricao,8,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 If &Resto <= 1 &Digito = 0 else &Digito = 11 - &Resto Endif If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Return endif
//2º Dígito &Calculo = val(Substr(&Inscricao,1,1))*4 + val(Substr(&Inscricao,2,1))*3 + val(Substr(&Inscricao,3,1))*2 + val(Substr(&Inscricao,4,1))*7 + val(Substr(&Inscricao,5,1))*6 + val(Substr(&Inscricao,6,1))*5 + val(Substr(&Inscricao,7,1))*4 + val(Substr(&Inscricao,8,1))*3 + val(Substr(&Inscricao,9,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 If &Resto <= 1 &Digito = 0 Else &Digito = 11 - &Resto Endif
If val(substr(&Inscricao,10,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Endif Endif return Endif
//Pernambuco If &Uf = 'PE'
&Inscricao = substr(&Inscricao,3,14)
If len(&Inscricao) <> 14 &InscricaoValida = 'N' Else
&Calculo = val(substr(&Inscricao,1,1))*5 + val(Substr(&Inscricao,2,1))*4 + val(Substr(&Inscricao,3,1))*3 + val(Substr(&Inscricao,4,1))*2 + val(Substr(&Inscricao,5,1))*1 + val(Substr(&Inscricao,6,1))*9 + val(Substr(&Inscricao,7,1))*8 + val(Substr(&Inscricao,8,1))*7 + val(Substr(&Inscricao,9,1))*6 + val(Substr(&Inscricao,10,1))*5 + val(Substr(&Inscricao,11,1))*4 + val(Substr(&Inscricao,12,1))*3 + val(Substr(&Inscricao,13,1))*2
&Resto = &Calculo - int(&Calculo/11)*11 &Digito = 11 - &Resto // // If &Digito > 9 // &Digito = &Digito - 10 // Endif
if &Resto <= 1 &Digito = 0 endif
If val(substr(&Inscricao,14,1)) = &Digito if &CliInsAux.Length() <= 9 RetornaSoNumeros.Call(&CliInsAux, &NewInscricao) &InscricaoValida = 'S' &NewInscricao = padL(&NewInscricao, 9, '0') Else &InscricaoValida = 'S' &NewInscricao = &Inscricao Endif Else &InscricaoValida = 'N' Endif Endif return Endif
//Piauí If &Uf = 'PI' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 &InscricaoValida = 'N' Else do 'Soma' If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif return Endif
//Rio de Janeiro If &Uf = 'RJ' &Inscricao = substr(&Inscricao,9,8)
If len(&Inscricao) <> 8 &InscricaoValida = 'N' Else &Calculo = val(substr(&Inscricao,1,1))*2 + val(substr(&Inscricao,2,1))*7 + val(substr(&Inscricao,3,1))*6 + val(substr(&Inscricao,4,1))*5 + val(substr(&Inscricao,5,1))*4 + val(substr(&Inscricao,6,1))*3 + val(substr(&Inscricao,7,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 If &Resto <= 1 &Digito = 0 Else &Digito = 11 - &Resto Endif If val(substr(&Inscricao,8,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif Return Endif
//Rio Grande do Norte If &Uf = 'RN' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 &InscricaoValida = 'N' Else do 'Soma' If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif return Endif
//Rio Grande do Sul If &Uf = 'RS' &Inscricao = substr(&Inscricao,7,10)
If len(&Inscricao) <> 10 &InscricaoValida = 'N' Else &ClInsc = &Inscricao &Inscricao = substr(&Inscricao,2,9) do 'Soma' &Inscricao = &ClInsc &Calculo = &Calculo + val(substr(&Inscricao,1,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 If &Resto <= 1 &Digito = 0 Else &Digito = 11 - &Resto Endif If val(substr(&Inscricao,10,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif return Endif
//Rondônia If &Uf = 'RO' &Inscricao = substr(&Inscricao,3,14)
If len(&Inscricao) <> 14 &InscricaoValida = 'N'
Else &Calculo = val(substr(&Inscricao,1,1))*6 + val(substr(&Inscricao,2,1))*5 + val(substr(&Inscricao,3,1))*4 + val(substr(&Inscricao,4,1))*3 + val(substr(&Inscricao,5,1))*2 + val(substr(&Inscricao,6,1))*9 + val(substr(&Inscricao,7,1))*8 + val(substr(&Inscricao,8,1))*7 + val(substr(&Inscricao,9,1))*6 + val(substr(&Inscricao,10,1))*5 + val(substr(&Inscricao,11,1))*4 + val(substr(&Inscricao,12,1))*3 + val(substr(&Inscricao,13,1))*2 &Resto = &Calculo - int(&Calculo/11)*11 &Digito = 11 - &Resto If &Digito > 9 &Digito = &Digito - 10 Endif If val(substr(&Inscricao,14,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif return Endif
//Roraima If &Uf = 'RR' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 &InscricaoValida = 'N' Else &Calculo = val(substr(&Inscricao,1,1))*1 + val(substr(&Inscricao,2,1))*2 + val(substr(&Inscricao,3,1))*3 + val(substr(&Inscricao,4,1))*4 + val(substr(&Inscricao,5,1))*5 + val(substr(&Inscricao,6,1))*6 + val(substr(&Inscricao,7,1))*7 + val(substr(&Inscricao,8,1))*8 &Resto = &Calculo - int(&Calculo/9)*9 &Digito = &Resto If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' endif endif return Endif
//Santa Catarina If &Uf = 'SC' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 &InscricaoValida = 'N' else do 'Soma' If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif Endif return endif
//São Paulo If &Uf = 'SP' //Verificador de inscricao para industriais e comerciantes. Para São Paulo, existe outro método de //cálculo para inscricao de produtores rurais, mas creio que isso não se aplica neste caso &Inscricao = substr(&Inscricao,5,12)
If len(&Inscricao) <> 12 &InscricaoValida = 'N' Else //1º Dígito = 9ª posição &Calculo = val(substr(&Inscricao,1,1))*1 + val(substr(&Inscricao,2,1))*3 + val(substr(&Inscricao,3,1))*4 + val(substr(&Inscricao,4,1))*5 + val(substr(&Inscricao,5,1))*6 + val(substr(&Inscricao,6,1))*7 + val(substr(&Inscricao,7,1))*8 + val(substr(&Inscricao,8,1))*10 &Resto = &Calculo - int(&Calculo/11)*11 If &Resto = 10 &Digito = 0 Else if &Resto = 11 &Digito = 1 Else &Digito = &Resto Endif Endif If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Return Endif //2º Dígito = 12ª posição &ClInsc = &Inscricao &Inscricao = substr(&Inscricao,4,12) do 'Soma' &Inscricao = &ClInsc &Calculo += val(substr(&Inscricao,1,1))*3 +val(substr(&Inscricao,2,1))*2 + val(substr(&Inscricao,3,1))*10 &Resto = &Calculo - int(&Calculo/11)*11 If &Resto = 10 &Digito = 0 Else If &Resto = 11 &Digito = 1 else &Digito = &Resto Endif Endif If val(substr(&Inscricao,12,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Endif Endif return Endif
//Sergipe If &Uf = 'SE' &Inscricao = substr(&Inscricao,8,9)
If len(&Inscricao) <> 9 &InscricaoValida = 'N' Else &ClInsc = &Inscricao &Inscricao = substr(&Inscricao,1,8) do 'Soma' &Inscricao = &ClInsc If val(substr(&Inscricao,9,1)) = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao else &InscricaoValida = 'N' Endif Endif return endif
//Tocantins If &Uf = 'TO' &inscricaovalor = val(&Inscricao) &Inscricao = trim(str(&inscricaovalor) )
If len(&Inscricao) = 9 or len(&Inscricao) = 11 &ClInsc = &Inscricao if len(&Inscricao) = 11 &Inscricao = substr(&Inscricao,1,2) + substr(&Inscricao,5,7) &DigitoAux = val(substr(&Inscricao,11,1)) else &DigitoAux = val(substr(&Inscricao,9,1)) Endif
do 'Soma' &Inscricao = &ClInsc If &DigitoAux = &Digito &InscricaoValida = 'S' &NewInscricao = &Inscricao Else &InscricaoValida = 'N' Endif else &InscricaoValida = 'N' Endif return Endif
Sub 'Soma' &Calculo = val(substr(&Inscricao,1,1))*9 + val(substr(&Inscricao,2,1))*8 + val(substr(&Inscricao,3,1))*7 + val(substr(&Inscricao,4,1))*6 + val(substr(&Inscricao,5,1))*5 + val(substr(&Inscricao,6,1))*4 + val(substr(&Inscricao,7,1))*3 + val(substr(&Inscricao,8,1))*2
&Resto = &Calculo - int(&Calculo/11)*11
&Digito = 11-&Resto If &Resto <= 1 &Digito = 0 Else &Digito = 11-&Resto Endif Endsub
